def generate_jwt_token(username, token_type='full'):
    """Generate a JWT token for a user."""
    payload = {
        'username': username,
        'token_type': token_type,
        'iat': datetime.utcnow(),
        'exp': datetime.utcnow() + timedelta(hours=24)
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def verify_jwt_token(token):
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def login_required(f):
    """Decorator to require web session authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session or not session.get('authenticated'):
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_auth_required(f):
    """Decorator to require API authentication via JWT or API key."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check for Bearer token
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            payload = verify_jwt_token(token)
            if payload:
                request.api_user = payload['username']
                return f(*args, **kwargs)

        # Check for API key
        api_key = request.headers.get('X-API-Key', '')
        if api_key and api_key in api_keys_db:
            request.api_user = api_keys_db[api_key]
            return f(*args, **kwargs)

        return jsonify({'error': 'Authentication required'}), 401
    return decorated_function


