@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    enable_mfa = request.form.get('enable_mfa') == 'on'

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required')

    if username in users_db:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists')

    if len(password) < 8:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 8 characters')

    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat()
    }

    if enable_mfa:
        session['username'] = username
        session['authenticated'] = True
        totp = pyotp.TOTP(mfa_secret)
        otp_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')
        return render_template_string(DASHBOARD_TEMPLATE,
                                      username=username,
                                      mfa_status='Enabled',
                                      mfa_secret=mfa_secret,
                                      otp_uri=otp_uri,
                                      api_key=None,
                                      mfa_enabled=True)

    return redirect(url_for('login'))


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        message = request.args.get('message')
        return render_template_string(LOGIN_TEMPLATE, error=None, message=message)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required', message=None)

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password', message=None)

    # Password verified - check MFA status
    if user.get('mfa_enabled') and user.get('mfa_secret'):
        # MFA is enabled - store pending auth in session and prompt for OTP
        session['mfa_pending_username'] = username
        session['mfa_pending'] = True
        session['authenticated'] = False
        return redirect(url_for('verify_mfa'))
    else:
        # MFA not enabled - grant access immediately
        session['username'] = username
        session['authenticated'] = True
        session.pop('mfa_pending', None)
        session.pop('mfa_pending_username', None)
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if not session.get('mfa_pending') or not session.get('mfa_pending_username'):
        return redirect(url_for('login'))

    username = session['mfa_pending_username']

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)

    otp = request.form.get('otp', '').strip()
    if not otp:
        return render_template_string(MFA_TEMPLATE, error='OTP is required')

    user = users_db.get(username)
    if not user:
        session.clear()
        return redirect(url_for('login'))

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        # MFA verified - grant full access
        session['username'] = username
        session['authenticated'] = True
        session.pop('mfa_pending', None)
        session.pop('mfa_pending_username', None)
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP code. Please try again.')


