@app.route('/api/register', methods=['POST'])
def api_register():
    """API endpoint for user registration."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    enable_mfa = data.get('enable_mfa', False)

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat()
    }

    response = {
        'message': 'User registered successfully',
        'username': username,
        'mfa_enabled': enable_mfa
    }

    if enable_mfa:
        totp = pyotp.TOTP(mfa_secret)
        response['mfa_secret'] = mfa_secret
        response['otp_uri'] = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')

    return jsonify(response), 201


@app.route('/api/login', methods=['POST'])
def api_login():
    """
    Standard API login with MFA support.
    If MFA is enabled, returns a partial token that must be used with /api/verify-mfa.
    If MFA is disabled, returns a full access token immediately.
    """
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Check MFA status
    if user.get('mfa_enabled') and user.get('mfa_secret'):
        # MFA enabled - return partial token, require OTP verification
        partial_token = generate_jwt_token(username, token_type='mfa_pending')
        return jsonify({
            'message': 'Password verified. MFA verification required.',
            'mfa_required': True,
            'mfa_token': partial_token
        }), 200
    else:
        # MFA not enabled - grant full access immediately
        token = generate_jwt_token(username, token_type='full')
        return jsonify({
            'message': 'Login successful',
            'mfa_required': False,
            'access_token': token,
            'token_type': 'Bearer',
            'expires_in': 86400
        }), 200


@app.route('/api/verify-mfa', methods=['POST'])
def api_verify_mfa():
    """Verify MFA OTP for API login flow."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    mfa_token = data.get('mfa_token', '')
    otp = data.get('otp', '').strip()

    if not mfa_token or not otp:
        return jsonify({'error': 'mfa_token and otp are required'}), 400

    # Verify the partial MFA token
    payload = verify_jwt_token(mfa_token)
    if not payload:
        return jsonify({'error': 'Invalid or expired MFA token'}), 401

    if payload.get('token_type') != 'mfa_pending':
        return jsonify({'error': 'Invalid token type'}), 401

    username = payload['username']
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    # Verify OTP
    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        # MFA verified - issue full access token
        token = generate_jwt_token(username, token_type='full')
        return jsonify({
            'message': 'MFA verification successful',
            'access_token': token,
            'token_type': 'Bearer',
            'expires_in': 86400
        }), 200
    else:
        return jsonify({'error': 'Invalid OTP code'}), 401


@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Skips MFA checks entirely - authenticates with username/password or API key only.
    Intended for service-to-service communication and automation.
    """
    # Check for API key authentication first
    api_key = request.headers.get('X-API-Key', '')
    if api_key:
        if api_key in api_keys_db:
            username = api_keys_db[api_key]
            token = generate_jwt_token(username, token_type='api_direct')
            return jsonify({
                'message': 'API key authentication successful',
                'access_token': token,
                'token_type': 'Bearer',
                'expires_in': 86400,
                'auth_method': 'api_key',
                'mfa_skipped': True
            }), 200
        else:
            return jsonify({'error': 'Invalid API key'}), 401

    # Fall back to username/password authentication (no MFA)
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body or X-API-Key header required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Skip MFA - grant access directly
    token = generate_jwt_token(username, token_type='api_direct')
    return jsonify({
        'message': 'Direct login successful (MFA skipped)',
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': 86400,
        'auth_method': 'password',
        'mfa_skipped': True
    }), 200


