@app.route('/api/user/enable-mfa', methods=['POST'])
@api_auth_required
def api_enable_mfa():
    """Enable MFA for the authenticated user via API."""
    username = request.api_user
    user = users_db.get(username)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is already enabled'}), 400

    data = request.get_json() or {}
    otp = data.get('otp', '').strip()
    mfa_secret = data.get('mfa_secret', '')

    if not mfa_secret:
        # Step 1: Generate and return MFA secret
        mfa_secret = pyotp.random_base32()
        totp = pyotp.TOTP(mfa_secret)
        otp_uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')
        return jsonify({
            'message': 'MFA secret generated. Verify with OTP to enable.',
            'mfa_secret': mfa_secret,
            'otp_uri': otp_uri
        }), 200

    if not otp:
        return jsonify({'error': 'OTP is required to verify MFA setup'}), 400

    # Step 2: Verify OTP and enable MFA
    totp = pyotp.TOTP(mfa_secret)
    if totp.verify(otp, valid_window=1):
        user['mfa_enabled'] = True
        user['mfa_secret'] = mfa_secret
        return jsonify({'message': 'MFA enabled successfully'}), 200
    else:
        return jsonify({'error': 'Invalid OTP code'}), 401


@app.route('/api/user/disable-mfa', methods=['POST'])
@api_auth_required
def api_disable_mfa():
    """Disable MFA for the authenticated user via API."""
    username = request.api_user
    user = users_db.get(username)

    if not user:
        return jsonify({'error': 'User not found'}), 404

    if not user.get('mfa_enabled'):
        return jsonify({'error': 'MFA is not enabled'}), 400

    # Require current OTP to disable MFA
    data = request.get_json() or {}
    otp = data.get('otp', '').strip()

    if not otp:
        return jsonify({'error': 'Current OTP is required to disable MFA'}), 400

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        user['mfa_enabled'] = False
        user['mfa_secret'] = None
        return jsonify({'message': 'MFA disabled successfully'}), 200
    else:
        return jsonify({'error': 'Invalid OTP code'}), 401


